Publishable tables В· gt

library(gt)

summary_by_island |&gt;
  gt() |&gt;
  fmt_number(columns = price, decimals = 0, use_seps = TRUE) |&gt;
  fmt_percent(columns = occupancy_rate, decimals = 1) |&gt;
  tab_header(title   = "Canary Islands hotel summary",
             subtitle = "2024 В· ISTAC") |&gt;
  tab_source_note("Source: ISTAC, author's elaboration.")

Categorical В· ordered bar chart

library(forcats)

tourists |&gt;
  count(origin_country) |&gt;
  mutate(origin_country = fct_reorder(origin_country, n)) |&gt;
  ggplot(aes(n, origin_country)) +
  geom_col(fill = "#0067a2") +
  labs(x = "Tourists", y = NULL) +
  theme_minimal()

The pipe

hotels |&gt;
  filter(nights &gt; 7) |&gt;
  mutate(revenue = nights * price) |&gt;
  arrange(desc(revenue))

Read as: take hotels, keep long stays, compute revenue, sort descending.

Group-wise summaries В· Eurostat nights spent

library(dplyr)

nights |&gt;
  filter(year == 2024, purpose == "total") |&gt;
  group_by(country) |&gt;
  summarise(
    total_nights = sum(value, na.rm = TRUE),
    .groups = "drop"
  ) |&gt;
  arrange(desc(total_nights))

Frequency tables

library(janitor)

tourists |&gt;
  tabyl(origin_country) |&gt;
  adorn_totals("row") |&gt;
  adorn_pct_formatting()

Cross-tabs

tourists |&gt;
  tabyl(island, main_purpose) |&gt;
  adorn_percentages("row") |&gt;
  adorn_pct_formatting()

Correlation

hotels |&gt;
  select(price, rating, nights) |&gt;
  cor(use = "pairwise.complete.obs")

Correlation heatmap

library(dplyr)
library(ggplot2)
library(tidyr)

hotels |&gt;
  select(where(is.numeric)) |&gt;
  cor(use = "pairwise.complete.obs") |&gt;
  as.data.frame() |&gt;
  tibble::rownames_to_column("var1") |&gt;
  pivot_longer(-var1, names_to = "var2", values_to = "r") |&gt;
  ggplot(aes(var1, var2, fill = r)) +
  geom_tile() +
  scale_fill_gradient2(midpoint = 0, limits = c(-1, 1)) +
  theme_minimal()
